// Package static provides static file serving for embedded frontend assets.
//
// Registration Order Requirements:
// API/WebSocket/Swagger routes MUST be registered before this module.
// This module registers a wildcard catch-all route for SPA fallback.
// Fiber matches exact routes before wildcards, ensuring API routes take priority.
package static

import (
	"mime"
	"net/http"
	"path/filepath"
	"strings"

	"github.com/gofiber/fiber/v3"
	"go.uber.org/zap"
)

// spaShellFile is the name of the SPA shell HTML file generated by TanStack Start.
const spaShellFile = "_shell.html"

// Handler serves static frontend files using embedded filesystem.
type Handler struct {
	fs      http.FileSystem
	enabled bool
	logger  *zap.Logger
}

// NewHandler creates a static file handler.
func NewHandler(logger *zap.Logger) *Handler {
	fs, err := getFileSystem()
	if err != nil {
		logger.Warn("frontend not embedded, static serving disabled",
			zap.Error(err),
			zap.String("hint", "build with -tags embed after running pnpm build in web/"),
		)
		return &Handler{
			fs:      nil,
			enabled: false,
			logger:  logger,
		}
	}
	return &Handler{
		fs:      fs,
		enabled: true,
		logger:  logger,
	}
}

// IsEnabled returns whether static serving is available.
func (h *Handler) IsEnabled() bool {
	return h.enabled
}

// RegisterRoutes registers static file routes on the Fiber app.
// Routes are registered in order: exact routes first, then SPA fallback.
// Fiber v3 matches exact routes before wildcards/middleware.
//
// IMPORTANT: API/WebSocket/Swagger routes must be registered before calling this function.
func RegisterRoutes(app *fiber.App, handler *Handler) {
	if !handler.enabled {
		// Frontend not built - only intercept frontend-specific paths
		// This allows API/WebSocket/Swagger routes to work normally
		frontendPaths := []string{"/", "/client/*", "/assets/*", "/favicon.ico", "/logo192.png", "/logo512.png", "/manifest.json", "/robots.txt"}
		for _, p := range frontendPaths {
			app.Get(p, func(c fiber.Ctx) error {
				handler.logger.Debug("frontend not available, returning 503",
					zap.String("path", c.Path()),
				)
				return c.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
					"error":   "Frontend not built",
					"hint":    "Run 'pnpm build' in web/ directory first, then build with -tags embed.",
					"docs":    "https://github.com/ryuyb/litchi#development",
				})
			})
		}
		return
	}

	// Serve client assets with long cache (hashed filenames)
	app.Get("/client/assets/*", func(c fiber.Ctx) error {
		path := filepath.Clean(c.Path()[1:]) // Clean path for safety
		return handler.serveFile(c, path, true)
	})

	// Serve shared assets
	app.Get("/assets/*", func(c fiber.Ctx) error {
		path := filepath.Clean(c.Path()[1:])
		return handler.serveFile(c, path, true)
	})

	// Serve static root files (exact routes - matched before wildcard)
	app.Get("/favicon.ico", func(c fiber.Ctx) error {
		return handler.serveFile(c, "favicon.ico", false)
	})
	app.Get("/logo192.png", func(c fiber.Ctx) error {
		return handler.serveFile(c, "logo192.png", false)
	})
	app.Get("/logo512.png", func(c fiber.Ctx) error {
		return handler.serveFile(c, "logo512.png", false)
	})
	app.Get("/manifest.json", func(c fiber.Ctx) error {
		return handler.serveFile(c, "manifest.json", false)
	})
	app.Get("/robots.txt", func(c fiber.Ctx) error {
		return handler.serveFile(c, "robots.txt", false)
	})

	// SPA fallback: catch-all route for client-side routing
	// Uses wildcard route (not middleware) so exact routes above take priority
	//
	// NOTE: This wildcard route will match all unmatched paths.
	// API/WebSocket/Swagger routes must be registered BEFORE this module
	// to ensure they are matched first (Fiber: exact routes before wildcards).
	app.Get("/*", func(c fiber.Ctx) error {
		path := c.Path()

		// Safety check: return 404 for API/WebSocket/Swagger paths
		// These should have been handled by routes registered before this module.
		// If we reach here, it means no handler matched.
		if strings.HasPrefix(path, "/api") ||
			strings.HasPrefix(path, "/ws") ||
			strings.HasPrefix(path, "/swagger") ||
			path == "/health" {
			return c.Status(fiber.StatusNotFound).JSON(fiber.Map{
				"error": "Not found",
			})
		}

		return handler.serveFile(c, spaShellFile, false)
	})
}

func (h *Handler) serveFile(c fiber.Ctx, path string, immutable bool) error {
	// If requesting root or directory, serve SPA shell instead
	file, err := h.fs.Open(path)
	if err != nil {
		return c.Status(fiber.StatusNotFound).SendString("File not found")
	}

	stat, err := file.Stat()
	if err != nil {
		file.Close()
		return c.Status(fiber.StatusInternalServerError).SendString("Failed to stat file")
	}

	// Handle directory - serve SPA shell for client-side routing
	if stat.IsDir() {
		file.Close()
		// Open SPA shell
		shellFile, err := h.fs.Open(spaShellFile)
		if err != nil {
			return c.Status(fiber.StatusNotFound).SendString("SPA shell not found")
		}
		defer shellFile.Close()

		c.Set("Content-Type", "text/html; charset=utf-8")
		c.Set("Cache-Control", "no-cache")
		return c.SendStream(shellFile)
	}

	// Regular file - stream it with proper headers
	contentType := mime.TypeByExtension(filepath.Ext(path))
	if contentType == "" {
		contentType = "application/octet-stream"
	}
	c.Set("Content-Type", contentType)

	if immutable {
		c.Set("Cache-Control", "public, max-age=31536000, immutable")
	} else {
		c.Set("Cache-Control", "no-cache")
	}

	// Stream file content - defer close after successful send
	defer file.Close()
	return c.SendStream(file)
}